import React from 'react';
import { Tabs, Tab, Box } from '@mui/material';
import { Link, useLocation } from 'react-router-dom';

function Navigation() {
  const location = useLocation();

  const getCurrentTab = () => {
    switch (location.pathname) {
      case '/issuer':
        return 1;
      case '/verifier':
        return 2;
      case '/wallet':
        return 3;
      case '/enhanced':
        return 4;
      case '/admin':
      case '/admin/passport':
      case '/admin/csca':
      case '/admin/pkd':
      case '/admin/trust-anchor':
      case '/admin/master-lists':
      case '/admin/metrics':
        return 5;
      default:
        return 0;
    }
  };

  return (
    <Box sx={{ borderBottom: 1, borderColor: 'divider', mb: 3 }}>
      <Tabs value={getCurrentTab()} aria-label="navigation">
        <Tab label="Home" component={Link} to="/" />
        <Tab label="Issue" component={Link} to="/issuer" />
        <Tab label="Verify" component={Link} to="/verifier" />
        <Tab label="Wallet" component={Link} to="/wallet" />
        <Tab label="Advanced" component={Link} to="/enhanced" />
        <Tab label="Admin" component={Link} to="/admin" />
      </Tabs>
    </Box>
  );
}

export default Navigation;
